+#[must_use]
+pub fn agent_mail_pids_holding_file(path: &std::path::Path) -> Vec<u32> {
+    pids_holding_file(path)
+        .into_iter()
+        .filter(|pid| pid_is_agent_mail(*pid))
+        .collect()
